import React, { useState, useEffect } from 'react';
import { Mic, MicOff, Send, Pause, Play, Volume2, VolumeX, User, Bot, MessageSquare, FileText, BookOpen } from 'lucide-react';

interface Message {
  id: number;
  sender: 'user' | 'ai' | 'system';
  content: string;
  timestamp: Date;
}

interface Document {
  _id: string;
  name: string;
  type: 'contract' | 'evidence' | 'pleading' | 'correspondence';
  pages: number;
}

const CourtroomSimulation: React.FC = () => {
  const [messages, setMessages] = useState<Message[]>([]);
  const [inputMessage, setInputMessage] = useState('');
  const [isRecording, setIsRecording] = useState(false);
  const [isMuted, setIsMuted] = useState(false);
  const [activeTab, setActiveTab] = useState<'chat' | 'documents' | 'notes'>('chat');
  const [documents, setDocuments] = useState<Document[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');

  // Fetch documents from backend
  useEffect(() => {
    const fetchDocuments = async () => {
      try {
        setLoading(true);
        
        // Fetch real documents from backend API
        const response = await fetch('http://localhost:5000/api/courtroom/documents');
        const data = await response.json();
        
        if (data.success) {
          setDocuments(data.data);
        } else {
          setError('Failed to fetch documents: ' + data.message);
        }
        
        setLoading(false);
      } catch (err) {
        setError('Error fetching documents: ' + (err as Error).message);
        console.error('Error fetching documents:', err);
        setLoading(false);
      }
    };

    fetchDocuments();
  }, []);

  // Fetch initial messages from backend
  useEffect(() => {
    const fetchInitialMessages = async () => {
      try {
        const response = await fetch('http://localhost:5000/api/courtroom/messages');
        const data = await response.json();
        
        if (data.success) {
          setMessages(data.data);
        }
      } catch (err) {
        console.error('Error fetching initial messages:', err);
        // Set default messages if fetch fails
        setMessages([
          {
            id: 1,
            sender: 'system',
            content: 'Welcome to the CourtCraft courtroom simulation. You are representing the plaintiff in a contract dispute case.',
            timestamp: new Date()
          },
          {
            id: 2,
            sender: 'ai',
            content: 'Good morning, Counsel. I am Judge Sharma presiding over this matter. Please present your opening statement.',
            timestamp: new Date()
          }
        ]);
      }
    };

    fetchInitialMessages();
  }, []);

  const handleSendMessage = async () => {
    if (inputMessage.trim() === '') return;
    
    const newMessage: Message = {
      id: messages.length + 1,
      sender: 'user',
      content: inputMessage,
      timestamp: new Date()
    };
    
    setMessages([...messages, newMessage]);
    setInputMessage('');
    
    // Send message to backend and get AI response
    try {
      const response = await fetch('http://localhost:5000/api/courtroom/respond', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json'
        },
        body: JSON.stringify({ message: inputMessage })
      });
      
      const data = await response.json();
      
      if (data.success) {
        setMessages(prev => [...prev, data.data]);
      } else {
        // Fallback AI response if backend fails
        setTimeout(() => {
          const aiResponse: Message = {
            id: messages.length + 2,
            sender: 'ai',
            content: "Thank you for that statement, Counsel. The defendant would like to respond to your claims. Mr. Advocate for the defense, please present your counter-argument.",
            timestamp: new Date()
          };
          setMessages(prev => [...prev, aiResponse]);
        }, 2000);
      }
    } catch (err) {
      console.error('Error sending message:', err);
      // Fallback AI response if backend fails
      setTimeout(() => {
        const aiResponse: Message = {
          id: messages.length + 2,
          sender: 'ai',
          content: "Thank you for that statement, Counsel. The defendant would like to respond to your claims. Mr. Advocate for the defense, please present your counter-argument.",
          timestamp: new Date()
        };
        setMessages(prev => [...prev, aiResponse]);
      }, 2000);
    }
  };

  const toggleRecording = () => {
    setIsRecording(!isRecording);
  };

  const toggleMute = () => {
    setIsMuted(!isMuted);
  };

  const getDocumentIcon = (type: string) => {
    switch (type) {
      case 'contract': return <FileText className="w-5 h-5 text-blue-500" />;
      case 'evidence': return <FileText className="w-5 h-5 text-green-500" />;
      case 'pleading': return <FileText className="w-5 h-5 text-purple-500" />;
      case 'correspondence': return <FileText className="w-5 h-5 text-yellow-500" />;
      default: return <FileText className="w-5 h-5 text-gray-500" />;
    }
  };

  if (loading) {
    return (
      <div className="min-h-screen bg-gray-50 flex items-center justify-center">
        <div className="text-center">
          <div className="inline-block animate-spin rounded-full h-12 w-12 border-t-2 border-b-2 border-indigo-600 mb-4"></div>
          <p className="text-gray-600">Loading courtroom simulation...</p>
        </div>
      </div>
    );
  }

  if (error) {
    return (
      <div className="min-h-screen bg-gray-50 flex items-center justify-center">
        <div className="text-center py-12">
          <div className="bg-red-100 rounded-full w-16 h-16 flex items-center justify-center mx-auto mb-4">
            <svg className="w-8 h-8 text-red-600" fill="none" stroke="currentColor" viewBox="0 0 24 24" xmlns="http://www.w3.org/2000/svg">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 8v4m0 4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z"></path>
            </svg>
          </div>
          <h3 className="text-xl font-bold text-gray-900 mb-2">Error Loading Courtroom Simulation</h3>
          <p className="text-gray-600 mb-4">{error}</p>
          <button 
            className="bg-indigo-600 text-white px-6 py-3 rounded-lg hover:bg-indigo-700 transition duration-300 font-medium"
            onClick={() => window.location.reload()}
          >
            Try Again
          </button>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-gray-50">
      {/* Header */}
      <div className="bg-white shadow-sm">
        <div className="container mx-auto px-4 py-4">
          <div className="flex justify-between items-center">
            <div>
              <h1 className="text-2xl font-bold text-gray-900">Contract Dispute Case</h1>
              <p className="text-gray-600">Plaintiff vs. Defendant - Civil Court, Delhi</p>
            </div>
            <div className="flex items-center space-x-4">
              <div className="flex items-center bg-red-100 text-red-800 px-3 py-1 rounded-full">
                <div className="w-2 h-2 bg-red-500 rounded-full mr-2 animate-pulse"></div>
                <span className="text-sm font-medium">Recording</span>
              </div>
              <button className="bg-indigo-600 text-white px-4 py-2 rounded-lg hover:bg-indigo-700 transition duration-300">
                End Session
              </button>
            </div>
          </div>
        </div>
      </div>

      <div className="container mx-auto px-4 py-8">
        <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
          {/* Main Courtroom Area */}
          <div className="lg:col-span-2">
            <div className="bg-white rounded-xl shadow-sm overflow-hidden">
              {/* Courtroom Visualization */}
              <div className="bg-gradient-to-b from-amber-800 to-amber-900 h-64 relative">
                <div className="absolute inset-0 flex items-center justify-center">
                  {/* Judge's Bench */}
                  <div className="bg-amber-700 w-64 h-24 rounded-lg flex items-center justify-center shadow-lg">
                    <div className="text-center">
                      <div className="w-12 h-12 bg-white rounded-full flex items-center justify-center mx-auto mb-2">
                        <User className="w-6 h-6 text-amber-800" />
                      </div>
                      <p className="text-white font-medium">Hon. Judge Sharma</p>
                      <p className="text-amber-200 text-sm">Presiding</p>
                    </div>
                  </div>
                  
                  {/* Plaintiff Table */}
                  <div className="absolute left-8 bottom-8 bg-amber-100 w-48 h-20 rounded-lg flex items-center justify-center shadow">
                    <div className="text-center">
                      <div className="w-8 h-8 bg-indigo-600 rounded-full flex items-center justify-center mx-auto mb-1">
                        <User className="w-4 h-4 text-white" />
                      </div>
                      <p className="text-gray-900 font-medium text-sm">You (Plaintiff)</p>
                    </div>
                  </div>
                  
                  {/* Defendant Table */}
                  <div className="absolute right-8 bottom-8 bg-amber-100 w-48 h-20 rounded-lg flex items-center justify-center shadow">
                    <div className="text-center">
                      <div className="w-8 h-8 bg-red-600 rounded-full flex items-center justify-center mx-auto mb-1">
                        <User className="w-4 h-4 text-white" />
                      </div>
                      <p className="text-gray-900 font-medium text-sm">Defendant</p>
                    </div>
                  </div>
                </div>
              </div>
              
              {/* Chat Interface */}
              <div className="p-6">
                {/* Tabs */}
                <div className="flex border-b border-gray-200 mb-6">
                  <button
                    className={`pb-3 px-6 font-medium ${activeTab === 'chat' ? 'text-indigo-600 border-b-2 border-indigo-600' : 'text-gray-500'}`}
                    onClick={() => setActiveTab('chat')}
                  >
                    <MessageSquare className="w-5 h-5 inline mr-2" />
                    Courtroom Chat
                  </button>
                  <button
                    className={`pb-3 px-6 font-medium ${activeTab === 'documents' ? 'text-indigo-600 border-b-2 border-indigo-600' : 'text-gray-500'}`}
                    onClick={() => setActiveTab('documents')}
                  >
                    <FileText className="w-5 h-5 inline mr-2" />
                    Documents
                  </button>
                  <button
                    className={`pb-3 px-6 font-medium ${activeTab === 'notes' ? 'text-indigo-600 border-b-2 border-indigo-600' : 'text-gray-500'}`}
                    onClick={() => setActiveTab('notes')}
                  >
                    <BookOpen className="w-5 h-5 inline mr-2" />
                    Notes
                  </button>
                </div>
                
                {/* Chat Tab */}
                {activeTab === 'chat' && (
                  <div className="space-y-6">
                    {/* Messages */}
                    <div className="space-y-4 max-h-96 overflow-y-auto pr-2">
                      {messages.map(message => (
                        <div 
                          key={message.id} 
                          className={`flex ${message.sender === 'user' ? 'justify-end' : 'justify-start'}`}
                        >
                          <div 
                            className={`max-w-xs lg:max-w-md px-4 py-3 rounded-2xl ${
                              message.sender === 'user' 
                                ? 'bg-indigo-600 text-white rounded-br-none' 
                                : message.sender === 'ai'
                                  ? 'bg-gray-100 text-gray-900 rounded-bl-none'
                                  : 'bg-blue-100 text-blue-900 rounded-b-none'
                            }`}
                          >
                            <p className="text-sm">{message.content}</p>
                            <p className={`text-xs mt-1 ${message.sender === 'user' ? 'text-indigo-200' : 'text-gray-500'}`}>
                              {message.timestamp.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                            </p>
                          </div>
                        </div>
                      ))}
                    </div>
                    
                    {/* Input Area */}
                    <div className="flex items-end space-x-3">
                      <div className="flex-1 relative">
                        <textarea
                          value={inputMessage}
                          onChange={(e) => setInputMessage(e.target.value)}
                          onKeyDown={(e) => {
                            if (e.key === 'Enter' && !e.shiftKey) {
                              e.preventDefault();
                              handleSendMessage();
                            }
                          }}
                          placeholder="Type your response..."
                          className="w-full px-4 py-3 border border-gray-300 rounded-2xl focus:outline-none focus:ring-2 focus:ring-indigo-500 focus:border-transparent resize-none"
                          rows={2}
                        />
                      </div>
                      <div className="flex space-x-2">
                        <button
                          onClick={toggleRecording}
                          className={`p-3 rounded-full ${
                            isRecording 
                              ? 'bg-red-100 text-red-600 hover:bg-red-200' 
                              : 'bg-gray-100 text-gray-600 hover:bg-gray-200'
                          } transition duration-200`}
                        >
                          {isRecording ? <MicOff className="w-5 h-5" /> : <Mic className="w-5 h-5" />}
                        </button>
                        <button
                          onClick={handleSendMessage}
                          disabled={inputMessage.trim() === ''}
                          className="p-3 bg-indigo-600 text-white rounded-full hover:bg-indigo-700 disabled:opacity-50 disabled:cursor-not-allowed transition duration-200"
                        >
                          <Send className="w-5 h-5" />
                        </button>
                      </div>
                    </div>
                  </div>
                )}
                
                {/* Documents Tab */}
                {activeTab === 'documents' && (
                  <div className="space-y-4">
                    {documents.length > 0 ? (
                      documents.map(doc => (
                        <div key={doc._id} className="flex items-center p-4 border border-gray-200 rounded-lg hover:bg-gray-50 transition duration-200">
                          <div className="mr-4">
                            {getDocumentIcon(doc.type)}
                          </div>
                          <div className="flex-1">
                            <h4 className="font-medium text-gray-900">{doc.name}</h4>
                            <p className="text-sm text-gray-500 capitalize">{doc.type} • {doc.pages} pages</p>
                          </div>
                          <button className="text-indigo-600 hover:text-indigo-800 font-medium">
                            View
                          </button>
                        </div>
                      ))
                    ) : (
                      <div className="text-center py-12">
                        <div className="bg-gray-100 rounded-full w-16 h-16 flex items-center justify-center mx-auto mb-4">
                          <FileText className="w-8 h-8 text-gray-400" />
                        </div>
                        <h3 className="text-lg font-medium text-gray-900 mb-1">No documents available</h3>
                        <p className="text-gray-500">Documents for this case will appear here</p>
                      </div>
                    )}
                  </div>
                )}
                
                {/* Notes Tab */}
                {activeTab === 'notes' && (
                  <div className="space-y-4">
                    <textarea
                      placeholder="Take notes during your session..."
                      className="w-full h-64 px-4 py-3 border border-gray-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-indigo-500 focus:border-transparent resize-none"
                    />
                    <div className="flex justify-end">
                      <button className="bg-indigo-600 text-white px-6 py-2 rounded-lg hover:bg-indigo-700 transition duration-300">
                        Save Notes
                      </button>
                    </div>
                  </div>
                )}
              </div>
            </div>
          </div>
          
          {/* Sidebar */}
          <div className="space-y-6">
            {/* Controls */}
            <div className="bg-white rounded-xl shadow-sm p-6 border border-gray-100">
              <h3 className="font-bold text-gray-900 mb-4">Courtroom Controls</h3>
              <div className="space-y-4">
                <button
                  onClick={toggleMute}
                  className="w-full flex items-center justify-center p-3 bg-gray-100 hover:bg-gray-200 rounded-lg transition duration-200"
                >
                  {isMuted ? <VolumeX className="w-5 h-5 mr-2" /> : <Volume2 className="w-5 h-5 mr-2" />}
                  {isMuted ? 'Unmute' : 'Mute'}
                </button>
                <button className="w-full flex items-center justify-center p-3 bg-gray-100 hover:bg-gray-200 rounded-lg transition duration-200">
                  <Pause className="w-5 h-5 mr-2" />
                  Pause Session
                </button>
                <button className="w-full flex items-center justify-center p-3 bg-indigo-600 text-white hover:bg-indigo-700 rounded-lg transition duration-300">
                  <Play className="w-5 h-5 mr-2" />
                  Resume Session
                </button>
              </div>
            </div>
            
            {/* Case Information */}
            <div className="bg-white rounded-xl shadow-sm p-6 border border-gray-100">
              <h3 className="font-bold text-gray-900 mb-4">Case Information</h3>
              <div className="space-y-3">
                <div>
                  <p className="text-sm text-gray-500">Case Type</p>
                  <p className="font-medium">Contract Dispute</p>
                </div>
                <div>
                  <p className="text-sm text-gray-500">Parties</p>
                  <p className="font-medium">Plaintiff vs. Defendant</p>
                </div>
                <div>
                  <p className="text-sm text-gray-500">Filed On</p>
                  <p className="font-medium">October 15, 2025</p>
                </div>
                <div>
                  <p className="text-sm text-gray-500">Status</p>
                  <span className="inline-block bg-green-100 text-green-800 text-xs font-medium px-2.5 py-0.5 rounded-full">
                    In Progress
                  </span>
                </div>
              </div>
            </div>
            
            {/* Timer */}
            <div className="bg-gradient-to-br from-indigo-500 to-purple-600 rounded-xl shadow-sm p-6 text-white">
              <h3 className="font-bold mb-2">Session Timer</h3>
              <div className="text-3xl font-mono font-bold">24:18</div>
              <p className="text-indigo-100 text-sm mt-1">Time elapsed</p>
              <div className="mt-4 w-full bg-white bg-opacity-20 rounded-full h-2">
                <div className="bg-white h-2 rounded-full" style={{ width: '45%' }}></div>
              </div>
              <p className="text-indigo-100 text-xs mt-2">45% of allocated time used</p>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default CourtroomSimulation;
